export default {
    generate(builder, project, config) {
        project.useProject('@user1/lib3_p')
        const lib1 = project.createTarget('lib1')
        lib1.LIBRARY = true
        lib1.addSource('lib1.c')
        lib1.addDependency('lib3')
        lib1.addExportIncludeDirectory('.')
    }
}
